--- /dev/null
+++ b/src/cache/layer.ts
@@ -0,0 +1,48 @@
+// First caching tier in this codebase: catalogue reads go through Redis
+// (TTL 300s) instead of hitting Postgres on every request. Trade-off
+// accepted: reads may be up to 5 minutes stale in exchange for DB load.
+import Redis from 'ioredis';
+export const cache = new Redis(process.env.REDIS_URL!);
+export const cached = async <T>(key: string, ttl: number, load: () => Promise<T>): Promise<T> => {
+  const hit = await cache.get(key);
+  if (hit) return JSON.parse(hit) as T;
+  const val = await load();
+  await cache.set(key, JSON.stringify(val), 'EX', ttl);
+  return val;
+};
+/* … key naming, invalidation hooks, metrics … */
